class Solution {
    public int minStartingIndex(String s, String pattern) {
        int m = pattern.length();
        int diffCount = 0;
        for (int i = 0; i < m; i++) {
            if (s.charAt(i) != pattern.charAt(i)) {
                diffCount++;
            }
        }
        if (diffCount <= 1) {
            return 0;
        }
        for (int i = m; i < s.length(); i++) {
            if (s.charAt(i) != pattern.charAt(i % m)) {
                diffCount++;
            }
            if (s.charAt(i - m) != pattern.charAt((i - m) % m)) {
                diffCount--;
            }
            if (diffCount <= 1) {
                return i - m + 1;
            }
        }
        return -1;
    }
}
